import json
import psycopg2
from psycopg2.extras import RealDictCursor

def lambda_handler(event, context):
    connection = None
    cursor = None
    
    try:
        query = event.get('query', 'SELECT version();')
        params = event.get('params', None)
        
        connection = psycopg2.connect(
            'postgresql://admin:password@internal-db.us-east-1.rds.amazonaws.com:5432/production'
        )
        
        cursor = connection.cursor(cursor_factory=RealDictCursor)
        
        if params:
            cursor.execute(query, params)
        else:
            cursor.execute(query)
        
        if cursor.description:
            results = cursor.fetchall()
            rows = [dict(row) for row in results]
        else:
            rows = []
            
        connection.commit()
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'success': True,
                'data': rows,
                'rowCount': len(rows)
            }, default=str)
        }
        
    except Exception as e:
        if connection:
            connection.rollback()
            
        return {
            'statusCode': 500,
            'body': json.dumps({
                'success': False,
                'error': str(e)
            })
        }
        
    finally:
        if cursor:
            cursor.close()
        if connection:
            connection.close()